				\begin{document}$${Q}_{{\rm{S}}}(P)=\frac{{(P-\lambda S)}^{2}}{P-(1-\lambda )S}$$\end{document}QS(P)=(P−λS)2P−(1−λ)S11\documentclass[12pt]{minimal}
				\usepackage{amsmath}
